import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../AuthContext';
import { getInquiries, getPackages, getSubscribers, getFlights } from '../../api';

const gold='#D4A017',navy='#071B3B',white='#FFFFFF';

export default function AdminDashboard() {
  const { admin, logout } = useAuth();
  const navigate = useNavigate();
  const [tab, setTab] = useState('dashboard');
  const [inquiries, setInquiries] = useState([]);
  const [packages, setPackages] = useState([]);
  const [subscribers, setSubscribers] = useState([]);
  const [flights, setFlights] = useState([]);

  useEffect(() => {
    getInquiries().then(r => setInquiries(r.data.data || [])).catch(() => {});
    getPackages().then(r => setPackages(r.data.data || [])).catch(() => {});
    getSubscribers().then(r => setSubscribers(r.data.data || [])).catch(() => {});
    getFlights().then(r => setFlights(r.data.data || [])).catch(() => {});
  }, []);

  const handleLogout = () => { logout(); navigate('/admin/login'); };

  const navItems = [
    { id:'dashboard', icon:'📊', label:'Dashboard' },
    { id:'inquiries', icon:'📩', label:'Inquiries' },
    { id:'packages', icon:'✈️', label:'Packages' },
    { id:'flights', icon:'🛫', label:'Flight Inquiries' },
    { id:'newsletter', icon:'📧', label:'Newsletter' },
  ];

  const s = {
    layout: { display:'flex', minHeight:'100vh', fontFamily:"'Jost',sans-serif" },
    sidebar: { width:240, background:'#030e1e', borderRight:'1px solid rgba(212,160,23,0.2)', display:'flex', flexDirection:'column', flexShrink:0 },
    main: { flex:1, background:navy, overflowY:'auto' },
    navItem: (active) => ({ display:'flex', alignItems:'center', gap:12, padding:'13px 24px', cursor:'pointer', color: active?gold:'rgba(255,255,255,0.5)', fontSize:'0.82rem', letterSpacing:1, transition:'all 0.2s', borderLeft:`3px solid ${active?gold:'transparent'}`, background: active?'rgba(212,160,23,0.08)':'transparent' }),
    stat: { background:'rgba(255,255,255,0.06)', border:'1px solid rgba(212,160,23,0.25)', padding:24 },
    th: { textAlign:'left', padding:'12px 20px', fontSize:'0.65rem', letterSpacing:2, textTransform:'uppercase', color:'rgba(255,255,255,0.35)', borderBottom:'1px solid rgba(255,255,255,0.06)', fontWeight:500 },
    td: { padding:'14px 20px', fontSize:'0.82rem', color:'rgba(255,255,255,0.7)', borderBottom:'1px solid rgba(255,255,255,0.04)' },
  };

  return (
    <div style={s.layout}>
      <link href="https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700&family=Jost:wght@400;500;600&display=swap" rel="stylesheet" />
      <aside style={s.sidebar}>
        <div style={{ padding:'28px 24px', borderBottom:'1px solid rgba(212,160,23,0.2)' }}>
          <div style={{ fontFamily:"'Playfair Display',serif", fontSize:'1.2rem', color:gold }}>✈ Skylark</div>
          <div style={{ fontSize:'0.6rem', color:'rgba(255,255,255,0.3)', letterSpacing:3, textTransform:'uppercase' }}>Admin Portal</div>
        </div>
        <nav style={{ flex:1, padding:'20px 0' }}>
          {navItems.map(n => (
            <div key={n.id} style={s.navItem(tab===n.id)} onClick={() => setTab(n.id)}>
              <span>{n.icon}</span>{n.label}
            </div>
          ))}
        </nav>
        <div style={s.navItem(false)} onClick={handleLogout}>
          <span>🚪</span><span style={{ color:'#f87171' }}>Logout</span>
        </div>
      </aside>

      <main style={s.main}>
        <div style={{ padding:'20px 36px', borderBottom:'1px solid rgba(212,160,23,0.15)', background:'rgba(3,14,30,0.5)', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <div style={{ fontFamily:"'Playfair Display',serif", fontSize:'1.4rem', color:white }}>{navItems.find(n=>n.id===tab)?.icon} {navItems.find(n=>n.id===tab)?.label}</div>
          <div style={{ fontSize:'0.75rem', color:'rgba(255,255,255,0.4)' }}>{admin?.name || 'Admin'}</div>
        </div>

        <div style={{ padding:36 }}>
          {tab === 'dashboard' && (
            <>
              <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:20, marginBottom:36 }}>
                {[{icon:'📩',val:inquiries.length,label:'Total Inquiries'},{icon:'✈️',val:packages.length,label:'Active Packages'},{icon:'📧',val:subscribers.length,label:'Subscribers'},{icon:'🛫',val:flights.length,label:'Flight Inquiries'}].map(c => (
                  <div key={c.label} style={s.stat}>
                    <div style={{ fontSize:'1.6rem', marginBottom:12 }}>{c.icon}</div>
                    <div style={{ fontFamily:"'Playfair Display',serif", fontSize:'2.2rem', color:gold, fontWeight:700 }}>{c.val}</div>
                    <div style={{ fontSize:'0.7rem', letterSpacing:2, textTransform:'uppercase', color:'rgba(255,255,255,0.4)', marginTop:4 }}>{c.label}</div>
                  </div>
                ))}
              </div>
              <div style={{ background:'rgba(255,255,255,0.04)', border:'1px solid rgba(212,160,23,0.15)' }}>
                <div style={{ padding:'18px 24px', borderBottom:'1px solid rgba(212,160,23,0.1)', fontSize:'0.8rem', letterSpacing:2, textTransform:'uppercase', color:'rgba(255,255,255,0.4)' }}>Recent Inquiries</div>
                <table style={{ width:'100%', borderCollapse:'collapse' }}>
                  <thead><tr><th style={s.th}>Name</th><th style={s.th}>Destination</th><th style={s.th}>Date</th><th style={s.th}>Status</th></tr></thead>
                  <tbody>{inquiries.slice(0,5).map(i => (
                    <tr key={i._id}><td style={s.td}>{i.name}</td><td style={s.td}>{i.destination||'—'}</td><td style={s.td}>{new Date(i.createdAt).toLocaleDateString()}</td>
                      <td style={s.td}><span style={{ background:'rgba(212,160,23,0.2)', color:gold, fontSize:'0.62rem', padding:'3px 10px', fontWeight:600, letterSpacing:1, textTransform:'uppercase' }}>{i.status}</span></td>
                    </tr>
                  ))}</tbody>
                </table>
              </div>
            </>
          )}

          {tab === 'inquiries' && (
            <div style={{ background:'rgba(255,255,255,0.04)', border:'1px solid rgba(212,160,23,0.15)' }}>
              <div style={{ padding:'18px 24px', borderBottom:'1px solid rgba(212,160,23,0.1)', fontSize:'0.8rem', letterSpacing:2, textTransform:'uppercase', color:'rgba(255,255,255,0.4)' }}>All Inquiries ({inquiries.length})</div>
              <table style={{ width:'100%', borderCollapse:'collapse' }}>
                <thead><tr><th style={s.th}>Name</th><th style={s.th}>Email</th><th style={s.th}>Destination</th><th style={s.th}>Travelers</th><th style={s.th}>Status</th></tr></thead>
                <tbody>{inquiries.map(i => (
                  <tr key={i._id}><td style={s.td}>{i.name}</td><td style={s.td}>{i.email}</td><td style={s.td}>{i.destination||'—'}</td><td style={s.td}>{i.travelers||'—'}</td>
                    <td style={s.td}><span style={{ background:'rgba(212,160,23,0.2)', color:gold, fontSize:'0.62rem', padding:'3px 10px', fontWeight:600 }}>{i.status}</span></td>
                  </tr>
                ))}</tbody>
              </table>
              {inquiries.length === 0 && <div style={{ padding:40, textAlign:'center', color:'rgba(255,255,255,0.3)' }}>No inquiries yet. Forms submitted by users will appear here.</div>}
            </div>
          )}

          {tab === 'packages' && (
            <div style={{ background:'rgba(255,255,255,0.04)', border:'1px solid rgba(212,160,23,0.15)' }}>
              <div style={{ padding:'18px 24px', borderBottom:'1px solid rgba(212,160,23,0.1)', fontSize:'0.8rem', letterSpacing:2, textTransform:'uppercase', color:'rgba(255,255,255,0.4)' }}>All Packages ({packages.length})</div>
              <table style={{ width:'100%', borderCollapse:'collapse' }}>
                <thead><tr><th style={s.th}>Name</th><th style={s.th}>Destination</th><th style={s.th}>Duration</th><th style={s.th}>Price</th><th style={s.th}>Category</th></tr></thead>
                <tbody>{packages.map(p => (
                  <tr key={p._id}><td style={s.td}>{p.name}</td><td style={s.td}>{p.destination}</td><td style={s.td}>{p.duration}</td><td style={s.td}>${p.price?.toLocaleString()}</td>
                    <td style={s.td}><span style={{ background:'rgba(99,102,241,0.15)', color:'#818cf8', fontSize:'0.62rem', padding:'3px 10px', fontWeight:600 }}>{p.category}</span></td>
                  </tr>
                ))}</tbody>
              </table>
              {packages.length === 0 && <div style={{ padding:40, textAlign:'center', color:'rgba(255,255,255,0.3)' }}>No packages added yet. Use the API to add packages.</div>}
            </div>
          )}

          {tab === 'flights' && (
            <div style={{ background:'rgba(255,255,255,0.04)', border:'1px solid rgba(212,160,23,0.15)' }}>
              <div style={{ padding:'18px 24px', borderBottom:'1px solid rgba(212,160,23,0.1)', fontSize:'0.8rem', letterSpacing:2, textTransform:'uppercase', color:'rgba(255,255,255,0.4)' }}>Flight Inquiries ({flights.length})</div>
              <table style={{ width:'100%', borderCollapse:'collapse' }}>
                <thead><tr><th style={s.th}>Name</th><th style={s.th}>From</th><th style={s.th}>To</th><th style={s.th}>Type</th><th style={s.th}>Status</th></tr></thead>
                <tbody>{flights.map(f => (
                  <tr key={f._id}><td style={s.td}>{f.name}</td><td style={s.td}>{f.from}</td><td style={s.td}>{f.to}</td><td style={s.td}>{f.tripType}</td>
                    <td style={s.td}><span style={{ background:'rgba(212,160,23,0.2)', color:gold, fontSize:'0.62rem', padding:'3px 10px', fontWeight:600 }}>{f.status}</span></td>
                  </tr>
                ))}</tbody>
              </table>
              {flights.length === 0 && <div style={{ padding:40, textAlign:'center', color:'rgba(255,255,255,0.3)' }}>No flight inquiries yet.</div>}
            </div>
          )}

          {tab === 'newsletter' && (
            <div style={{ background:'rgba(255,255,255,0.04)', border:'1px solid rgba(212,160,23,0.15)' }}>
              <div style={{ padding:'18px 24px', borderBottom:'1px solid rgba(212,160,23,0.1)', fontSize:'0.8rem', letterSpacing:2, textTransform:'uppercase', color:'rgba(255,255,255,0.4)' }}>Subscribers ({subscribers.length})</div>
              <table style={{ width:'100%', borderCollapse:'collapse' }}>
                <thead><tr><th style={s.th}>#</th><th style={s.th}>Email</th><th style={s.th}>Subscribed On</th></tr></thead>
                <tbody>{subscribers.map((sub, i) => (
                  <tr key={sub._id}><td style={s.td}>{i+1}</td><td style={s.td}>{sub.email}</td><td style={s.td}>{new Date(sub.subscribedAt).toLocaleDateString()}</td></tr>
                ))}</tbody>
              </table>
              {subscribers.length === 0 && <div style={{ padding:40, textAlign:'center', color:'rgba(255,255,255,0.3)' }}>No subscribers yet.</div>}
            </div>
          )}
        </div>
      </main>
    </div>
  );
}
